import React from "react";
import { useState } from "react";
import useUserStore from './useUserStore'; 
import "bootstrap-icons/font/bootstrap-icons.css";

function TableRecent() {
  const [range, setRange] = useState({ from: 0, to: 5, pgNumber: 1 });
  const { from: start, to: end, pgNumber: pgNum } = range;
  const { userID, setUserID } = useUserStore();

  let transactionHistory =[];

  async function transactionHistoryGetter() {
  const res = await fetch("http://localhost:5001/api/getAllTransactions",{
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({id:userID}),
  });
  transactionHistory = await res.json();
  // console.log(result);
  if (res.ok) {

    console.log("Transactions pulled!");
  } else {
     console.log("Something went wrong with pulling transactions.");
  }

  return transactionHistory;
}

// async function historyArraySetter() {
//   transactionHistory= await transactionHistoryGetter();
//  console.log(historyArraySetter);
// }





  const numOfPgs = Math.ceil(transactionHistoryGetter().length / 5);

  function nextPg() {
    setRange((prev) => {
      return {
        from: prev.from + 5,
        to: prev.to + 5,
        pgNumber: prev.pgNumber + 1,
      };
    });
  }

  function prevPg() {
    setRange((prev) => {
      return {
        from: prev.from - 5,
        to: prev.to - 5,
        pgNumber: prev.pgNumber - 1,
      };
    });
  }

  return (
    <div className="table-responsive">
      <table className="table table-bordered table-striped">
        <thead className="table-dark">
          <tr>
            <th>Number</th>
            <th>Category</th>
            <th>Amount</th>
            <th>Date</th>
            <th>Description</th>
            <th>Modify</th>
          </tr>
        </thead>
        {/* <tbody>
          {transactionHistory.slice(range.from, range.to).map((item, index) => (
